UIDressStore = class("UIDressStore", IGUILayout)

local curTableIndex = 0
local curSelectId = 0
local dressData = {}
local initTabFlag = 0
local changeFlag = 0

function UIDressStore:onLoad()

    self.layMain = self:getChildWindow("DressStore-Main", GUIType.Layout)
    self.layDetail = self:getChildWindow("DressStore-Detail", GUIType.Layout)
    self.layModel = self:getChildWindow("DressStore-Preview-Model", GUIType.Layout)
