function UIDressStore:register()
    self.btnClose:registerEvent(GUIEvent.ButtonClick, function()
        SoundUtil.playSound(SoundType.ClosePanel)
        self:hide()
    end)

    self.siResult:registerEvent(GUIEvent.TouchDown, function()
        if false then
            return false
        end
        self.siResult:SetVisible(false)
    end)

    self:registerDataCallBack("ShowDressStore", function()
        if curTableIndex ~= 0 or curTableIndex ~= 1 then
            if self.gvTabItems then
                local curitem = self.gvTabItems:getItem("index", curTableIndex)
                curitem.btnButton:SetChecked(false)
                curitem.btnButton:SetTouchable(true)
                local item = self.gvTabItems:getItem("index", 1)
                item.btnButton:SetChecked(true)
                item.btnButton:SetTouchable(false)
            end
        end
        GUIDressStore:show()
    end)

    self:registerDataCallBack("DressStoreData", function(data)
        for _, dress in pairs(data) do
            self:initDressData(dress)
        end
        if initTabFlag == 1 then
            self:showPanelByType(curTableIndex)
        else
            self:initTabs()
        end
    end, JsonBuilderProcessor)

    self:registerEvent(DressStoreTabChangeEvent, function(index)
        changeFlag = 1
        self:cbChangeState(index)
    end)

    self:registerEvent(UIDressStorePanItemChangeEvent, function(id)
        self:panelItemChange(id)
    end)

    self:registerEvent(ShowUseDressEvent, function(id)
        self:setUseDress(id)
    end)
end

function UIDressStore:initTabs()
    self.Tabs:CleanupChildren()
    local tabs = DressConfig:getDressTables()
    local len = 0
    local MinCount
    for _, k in pairs(tabs) do
        len = len + 1
    end
    if len > 5 then
        MinCount = len
    else
        MinCount = 5
    end
    if self.gvTabItems ~= nil then
        self.gvTabItems:destroy()
    end
    self.gvTabItems = IGUIGridView.new("DressStore-Content-Tabs-Item", self.Tabs)
    self.gvTabItems:setArea({ 0, 0 }, { 0, 0 }, { 1, 0 }, { 1, 0 })
    self.gvTabItems:setConfig(1, 1, 1)
    self.gvTabItems.root:SetHorizontalAlignment(HorizontalAlignment.Center)
    self.gvTabItems.root:SetVerticalAlignment(VerticalAlignment.Center)
    self.gvTabItems.root:SetClipChild(false)
    local TabSize = (self.Tabs:GetPixelSize().y - 1 - MinCount) / MinCount
    local TabWidth = self.Tabs:GetPixelSize().x
    local tabCount = 0
    local index = 0
    for _, tab in pairs(tabs) do
        tabCount = tabCount + 1
        index = index + 1
        local newNum = self:getNewCountByType(tab.Type)
        local item = UIDressStoreTableItem.new("DressStoreTab.json")
        item:setWidth({ 0, TabWidth })
        item:setHeight({ 0, TabSize })
        item:initTab(tab, newNum)
        item:setIndex(index)
        item:registerClick(tab.Type)
        self.gvTabItems:addItem(item)
    end
    local item = self.gvTabItems:getItem("index", 1)
    item.btnButton:SetChecked(true)
    self:initPanel()
    self:showPanelByType(1)
    initTabFlag = 1
end

function UIDressStore:onShow()
    local GuideWindow = GUIManager:getWindowByName("GuideSystem")
    if GuideWindow:IsVisible() then
        self:cbChangeState(1)
    end
end

function UIDressStore:cbChangeState(index)
    if index ~= curTableIndex then
        local curItem = self.gvTabItems:getItem("index", curTableIndex)
        if curItem ~= nil then
            curItem.btnButton:SetChecked(false)
            curItem.btnButton:SetTouchable(true)
        end
        local newItem = self.gvTabItems:getItem("index", index)
        if newItem ~= nil then
            newItem.btnButton:SetChecked(true)
            newItem.btnButton:SetTouchable(false)
        end
        self:initPanel()
        self:showPanelByType(index)
    end
end

function UIDressStore:initPanel()
    self.layPanel:CleanupChildren()
    if self.gvDreItems ~= nil then
        self.gvDreItems:destroy()
    end
    self.gvDreItems = IGUIGridView.new("DressStore-Content-Panels-Item", self.layPanel)
    self.gvDreItems:setArea({ 0, 0 }, { 0, 0 }, { 1, 0 }, { 1, 0 })
    self.gvDreItems:setConfig(6, 6, 4)
    self.gvDreItems.root:SetHorizontalAlignment(HorizontalAlignment.Center)
    self.gvDreItems.root:SetVerticalAlignment(VerticalAlignment.Center)

    local ContentSize = self.layPanel:GetPixelSize().x
    local ChildWidth = (ContentSize - 4 * 4) / 4
    local DressAdapter = require "hall.ui.adapter.DressAdapter"
    self.adapter = DressAdapter.new()
    self.adapter:setItemSize({ ChildWidth, math.floor(ChildWidth * 0.88) })
    self.gvDreItems:setAdapter(self.adapter)
end

function UIDressStore:showPanelByType(type)
    curTableIndex = type
    curSelectId = nil
    local dressConfig = DressConfig:getDressConfigByType(type)
    self.adapter:setData(dressConfig)
    if dressConfig and dressConfig[1] then
        local curItem = self.gvDreItems:getItem("Id", dressConfig[1].Id)
        if curItem then
            curItem:onClock()
        end
    end
end

function UIDressStore:panelItemChange(id)
    local statue = self:getStatuesById(curSelectId)
    local newStatue = self:getStatuesById(id)
    if curSelectId == nil then
        self.info:updateAndShow(id)
    elseif id ~= curSelectId and changeFlag ~= 1 then
        local curItem = self.gvDreItems:getItem("Id", curSelectId)
        if curItem == nil then
            curSelectId = id
            self.adapter:notifyDataChange()
            return false
        end
        if statue == 2 or statue == 1 then
            --1 = NOT_GET   2 = NEW
            curItem.siStatueBox:SetImage("set:dress_shop.json image:not_get")
        elseif statue == 0 then
            --0 = LOCK
            curItem.siStatueBox:SetImage("set:dress_shop.json image:lock")
        elseif statue == 3 or statue == 4 then
            curItem.siStatueBox:SetImage("set:dress_shop.json image:has_get")
        end
    end
    if changeFlag == 1 then
        changeFlag = 0
    end
    if newStatue ~= 0 then
        self.info:updateAndShow(id)
    else
        self.info:cleanInfo()
    end
    curSelectId = id
    self.adapter:notifyDataChange()
end

