function UIDressStore:initModel()
    local sex = PlayerManager:getClientPlayer():getSex()
    if sex <= 1 then
        self.awModel:SetActor1("boy.actor", "idle", -45)
    else
        self.awModel:SetActor1("girl.actor", "idle", -45)
    end
end

function UIDressStore:setUseDress(dressId)
    self.awModel:reflreshArmor(Game:getPlayer())
    local config = DressConfig:findStoreDressById(dressId)
    self.awModel:UseBodyPart(config.ModelActorBody, config.ModelActorBodyId)
    if "armor_head" == config.ModelActorBody then
        self.awModel:UseBodyPart("custom_hair", 0)
    end
end

function UIDressStore:initDressData(data)
    local dress = UIDressStore:getDressData(data.Id)
    if dress then
        if data.Status then
            dress.Status = data.Status
            if tonumber(dress.Status) == 5 then
                GUIStoreDressDetail:init(data.Id, data.Chip)
                local config = DressConfig:findStoreDressByItemId(data.Id)
                if config then
                    self.siResult:SetVisible(true)

                    self.siResultActor:SetActor("g1008_skin2.actor")
                    self.siResultActor:UseBodyPart("body", config.BodyId)
                end
            end
        end
        if data.Chip then
            dress.Chip = data.Chip
        end
    else
        dress = {}
        dress.Id = data.Id
        dress.Status = data.Status
        dress.Chip = data.Chip or 0
        table.insert(dressData, dress)
    end
end

function UIDressStore:changeStatue(id, statue)
    for i, item in pairs(dressData) do
        if item.Id == id then
            dressData[i].Status = statue
        end
    end
end

function UIDressStore:getStatuesById(id)
    for _, statue in pairs(dressData) do
        if statue.Id == id then
            return statue.Status
        end
    end
    return 0
end

function UIDressStore:getDressData(id)
    for _, dress in pairs(dressData) do
        if dress.Id == id then
            return dress
        end
    end
end

function UIDressStore:isSelect(id)
    if curSelectId == id then
        return true
    else
        return false
    end
end

function UIDressStore:getNewCountByType(type)
    local dress = DressConfig:findStoreDressByTabType(type)
    local count = 0
    for _, dre in pairs(dress) do
        local statue = self:getStatuesById(dre.Id)
        if statue == 2 then
            count = count + 1
        end
    end
    return count
end

return UIDressStore